    "id": "544",
    "title": "ALIMENTO MI PASION",
    "content": "<div align=\"center\"><strong><span style=\"font-size:130%;\">lunes, marzo 21, 2005<br /></span></strong><a name=\"111145572266668293\"></a><br /><strong><span style=\"font-size:130%;color:#009900;\">ALIMENTO MI PASION<br /></span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">Caminó mi juventud</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">por tu playa caliente,</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">la nostalgia viviente</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">siembra alguna virtud.</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">Trujillo a plenitud</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">alimento mi pasión,</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">se cinceló la ilusión</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">en tierra prodigiosa</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">fue la voz maravillosa</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">que desbordó mi corazón.</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;\">vahema</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;color:#330099;\">Lunes 25 de Marzo 2005</span></strong></div><div align=\"center\"><strong><span style=\"font-size:130%;color:#330099;\">SUCRE BOLIVIA<br /></span></strong></div>",
