    "content": "<div align=\"center\"><span style=\"font-size:180%;color:#009900;\"><strong>LIMA CIUDAD JARDIN</strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong></strong></span> </div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>LIMA CIUDAD JARDIN </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>DEL HABITO MORADO, </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>DEL SEÑOR CRUCIFICADO </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>DE SANTA ROSA Y MARTIN .</strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>ES UNA HISTORIA SIN FIN </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>DE PERRO, GATO, Y PERICOTE </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>AUNQUE UD. NO LO NOTE </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>PARA CURAR SUS MALES </strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong>BUSQUE BUENOS TAMALES</strong></span></div><div align=\"center\"><span style=\"font-size:130%;color:#ff0000;\"><strong> Y FRIASE SUS CAMOTES.</strong></span></div><div align=\"center\"><strong><span style=\"font-size:130%;color:#ff0000;\">VAHEMA</span></strong></div><div align=\"center\">OCTUBRE 2001</div><div align=\"center\">SUCRE BOLIVIA</div>",
