    "title": "EN TUS OJOS HAY UN GRITO",
    "content": "<p style=\"text-align: center;\">TU ROSTRO NO ES PINTURA</p>\r\n<p style=\"text-align: center;\">CONVERSAN TUS CABELLOS</p>\r\n<p style=\"text-align: center;\">LA LIBERTAD ES DURA</p>\r\n<p style=\"text-align: center;\">ENTRE VILES ATROPELLOS.</p>\r\n<p style=\"text-align: center;\">ALLÍ ESTÁN TUS MANOS,</p>\r\n<p style=\"text-align: center;\">ENTRE VOCES ENTERRADAS</p>\r\n<p style=\"text-align: center;\">ES LA SOMBRA DE UN HERMANO</p>\r\n<p style=\"text-align: center;\">CON LA GLORIA Y SUS ESPADAS.</p>\r\n<p style=\"text-align: center;\">EN TUS OJOS HAY UN GRITO</p>\r\n<p style=\"text-align: center;\">DE SONRISA RECORTADA</p>\r\n<p style=\"text-align: center;\">LA PALABRA ES ATADA</p>\r\n<p style=\"text-align: center;\">POR UN ROSTRO INVISIBLE</p>\r\n<p style=\"text-align: center;\">NO CONTESTES NADA</p>\r\n<p style=\"text-align: center;\">LA VERDAD ES INVENCIBLE</p>\r\n<p style=\"text-align: center;\">VAHEMA</p>\r\n<p style=\"text-align: center;\">27 DE SETIEMBRE 2000</p>",
